'use client';

import React, { useState } from 'react';

interface ObliczeniaWynik {
  daily: number;
  monthly: number;
  yearly: number;
}

export default function KalkulatorPage() {
  const [kwota, setKwota] = useState<number | ''>(1000);
  const [oprocentowanie, setOprocentowanie] = useState<number | ''>(5.0);
  const [wyniki, setWyniki] = useState<ObliczeniaWynik | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleOblicz = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setWyniki(null);

    if (!kwota || !oprocentowanie || Number(kwota) <= 0 || Number(oprocentowanie) <= 0) {
      setError('Proszę podać poprawne, dodatnie wartości dla kwoty i oprocentowania.');
      return;
    }

    setLoading(true);
    try {
      const url = `http://localhost:8080/api/calc?kwota=${kwota}&oprocentowanie=${oprocentowanie}`;
      const response = await fetch(url);

      if (!response.ok) throw new Error();

      const data: ObliczeniaWynik = await response.json();
      setWyniki(data);
    } catch {
      setError('Nie udało się połączyć z serwerem obliczeniowym.');
    } finally {
      setLoading(false);
    }
  };

  const formatPLN = (value: number) =>
    new Intl.NumberFormat('pl-PL', { style: 'currency', currency: 'PLN' }).format(value);

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] px-6">
      
      <div className="bg-white rounded-xl shadow-lg border border-gray-100 p-8 w-full max-w-md">
        
        <div className="text-center mb-6">
          <h1 className="text-2xl font-bold text-gray-900">Kalkulator Zysków 💰</h1>
          <p className="text-sm text-gray-500">Oblicz precyzyjnie zysk z obligacji lub lokaty</p>
        </div>

        <form onSubmit={handleOblicz} className="flex flex-col gap-5">
          
          <div className="flex flex-col gap-1">
            <label className="font-semibold text-sm text-gray-700">Kwota Inwestycji (PLN)</label>
            <input
              type="number"
              value={kwota}
              placeholder="np. 10000"
              onChange={(e) => setKwota(e.target.value === '' ? '' : Number(e.target.value))}
              className="px-4 py-3 border rounded-lg text-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>

          <div className="flex flex-col gap-1">
            <label className="font-semibold text-sm text-gray-700">Oprocentowanie (%)</label>
            <input
              type="number"
              step="0.01"
              value={oprocentowanie}
              placeholder="np. 6.5"
              onChange={(e) => setOprocentowanie(e.target.value === '' ? '' : Number(e.target.value))}
              className="px-4 py-3 border rounded-lg text-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="mt-2 bg-blue-600 text-white font-semibold py-3 rounded-lg hover:bg-blue-700 transition disabled:opacity-60"
          >
            {loading ? 'Obliczanie...' : 'Oblicz Zysk'}
          </button>
        </form>

        {error && (
          <div className="mt-5 p-3 bg-red-50 border border-red-300 text-red-600 text-sm rounded-lg text-center">
            ⚠️ {error}
          </div>
        )}

        {wyniki && (
          <div className="mt-6 p-5 bg-green-50 border border-green-300 rounded-xl">
            <h2 className="text-green-700 text-lg font-semibold text-center mb-3">
              Twoje Prognozowane Zyski:
            </h2>

            <div className="flex justify-between py-2 border-b border-dashed border-gray-300">
              <span className="text-gray-600">Zysk Dzienny:</span>
              <span className="font-bold text-green-700">{formatPLN(wyniki.daily)}</span>
            </div>

            <div className="flex justify-between py-2 border-b border-dashed border-gray-300">
              <span className="text-gray-600">Zysk Miesięczny:</span>
              <span className="font-bold text-green-700">{formatPLN(wyniki.monthly)}</span>
            </div>

            <div className="flex justify-between py-2">
              <span className="text-gray-600">Zysk Roczny:</span>
              <span className="font-extrabold text-green-800 text-xl">{formatPLN(wyniki.yearly)}</span>
            </div>
          </div>
        )}

      </div>

      <p className="text-xs text-gray-400 text-center mt-4 max-w-sm">
        * Wyliczenia mają charakter poglądowy i nie uwzględniają podatku Belki.
      </p>
    </div>
  );
}